// CANONICAL BSN program data — this file is the editable source of truth for the
// seed. Edit entries here (fill in verified requirements, add new schools), then run
// `npx tsx prisma/seed.ts` to push to the DB (idempotent upsert by `slug`).
//
// For the school-research routine, see docs/AGENT_ROUTINE.md. Field notes:
//   slug            stable key: `<state>-<university>-<city>` lowercased, non-alnum -> '-'
//   tier            'Local' | 'Top TX' | 'Top US'   region 'Arkansas' | 'Texas' | 'National'
//   requiredCourses array of course KEYS (not labels): ANAT_PHYS_1, ANAT_PHYS_2, MICRO,
//                   CHEM, STATS, NUTRITION, LIFESPAN, ENGLISH_COMP  (see lib/constants.ts)
//   examType        'TEAS' | 'HESI A2' | 'NLN PAX' | null   minExamScore = percent (0-100)
//   minOverallGPA / minScienceGPA   0.0-4.0 or null if unverified
//   dataQuality     'verified' | 'partial' | 'placeholder'
//                   verified   = confirmed directly from official program page
//                   partial    = sourced from published info but may be stale; spot-check before applying
//                   placeholder = no requirement data yet; fit scores are exploratory estimates only
export type SeedProgram = {
  slug: string; name: string; university: string; city: string; state: string
  isPublic: boolean; programType: string; isFlagship: boolean
  tier: 'Local' | 'Top TX' | 'Top US'; region: 'Arkansas' | 'Texas' | 'National'
  minOverallGPA: number | null; minScienceGPA: number | null; requiredCourses: string[]
  examType: string | null; minExamScore: number | null; casperRequired: boolean
  deadlines: string | null; notes: string | null
  // The school's official admissions / requirements page (real, working link).
  // Filled from official .edu sources by the per-state research agents; null until verified.
  officialUrl?: string | null
  // The nursing program's admissions contact email; null until verified.
  admissionEmail?: string | null
  dataQuality: 'verified' | 'partial' | 'placeholder'
  // Requirement fields whose values are AI estimates (scripts/estimate-requirements.ts),
  // not published data. MUST be cleared when a school is verified from official sources.
  estimatedFields?: string[]
}

